package tests;import base.BaseTestPlaywright;import org.junit.jupiter.api.Test;import java.nio.file.Paths;import static org.junit.jupiter.api.Assertions.assertTrue;public class HP04MarcarPedidoEntregadoPlaywrightTest extends BaseTestPlaywright {    @Test    void cocineroMarcaPedidoComoEntregado() {        page.navigate("https://ernest.xo.je/index.php?route=auth/login");        page.locator("input[name='username']").fill("cocinero");        page.locator("input[name='password']").fill("123");        page.locator("button[type='submit']").click();        page.waitForTimeout(2000);        long antes = page                .locator("button:has-text('Marcar como entregado')")                .count();        assertTrue(                antes > 0,                "No existe ningún pedido en preparación."        );        page.locator("button:has-text('Marcar como entregado')")                .first()                .click();        page.waitForTimeout(2000);        long despues = page                .locator("button:has-text('Marcar como entregado')")                .count();        assertTrue(                despues < antes,                "El pedido no fue marcado como entregado."        );        page.screenshot(                new com.microsoft.playwright.Page.ScreenshotOptions()                        .setPath(Paths.get(                                "evidencias/HP04-pedido-entregado.png"))                        .setFullPage(true)        );    }}